-- Student stories
('11111111-1111-1111-1111-111111111201', 'student', 'course', 'Ayesha Mahmood', 'ayesha.mahmood@example.com', '+923001112233', 5, 'Clear learning path', 'Mujhe course ka flow bohat clear laga. Har week ka task practical tha aur aisa laga ke real project par kaam kar rahi hun.', 'approved', now() - interval '165 days', now() - interval '165 days', now() - interval '165 days', now()),
('11111111-1111-1111-1111-111111111202', 'student', 'mentor', 'Hamza Qureshi', 'hamza.qureshi@example.com', '+923129998877', 5, 'Supportive mentors', 'Mentor ne har dafa achi tareeqay se samjhaya. Jab bhi atka, jaldi response mila aur direction clear ho gayi.', 'approved', now() - interval '160 days', now() - interval '160 days', now() - interval '160 days', now()),
('11111111-1111-1111-1111-111111111203', 'student', 'task_review', 'Areeba Khan', 'areeba.khan@example.com', '+923001998877', 4, 'Helpful task reviews', 'Task review se bohat help hui. Jo mistakes hoti thin un par proper notes mil jate thay aur next submission better hoti thi.', 'approved', now() - interval '155 days', now() - interval '155 days', now() - interval '155 days', now()),
('11111111-1111-1111-1111-111111111204', 'student', 'internship', 'Bilal Saeed', 'bilal.saeed@example.com', '+923214445566', 5, 'Internship ready', 'Internship wali guidance bohat useful thi. Practice ke baad mujhe Lahore ki aik software house me paid role mil gaya.', 'approved', now() - interval '150 days', now() - interval '150 days', now() - interval '150 days', now()),
('11111111-1111-1111-1111-111111111205', 'student', 'support', 'Zoya Iqbal', 'zoya.iqbal@example.com', '+923331234567', 4, 'Quick support', 'Jab bhi issue aya support team ne jaldi jawab diya. Is wajah se training ke dauran zyada tension nahi hui.', 'approved', now() - interval '145 days', now() - interval '145 days', now() - interval '145 days', now()),
('11111111-1111-1111-1111-111111111206', 'student', 'course', 'Sana Tariq', 'sana.tariq@example.com', '+923214221133', 5, 'Strong foundation', 'Main beginner thi, lekin yahan aa kar basics strong hue. Har topic practical examples ke sath samajh aya.', 'approved', now() - interval '140 days', now() - interval '140 days', now() - interval '140 days', now()),
('11111111-1111-1111-1111-111111111207', 'student', 'mentor', 'Usman Ali', 'usman.ali@example.com', '+923114889900', 5, 'Mentor accountability', 'Mentor ne regular follow-up rakha, jis se main apna portfolio time par complete kar saka aur focus bhi bana raha.', 'approved', now() - interval '135 days', now() - interval '135 days', now() - interval '135 days', now()),
('11111111-1111-1111-1111-111111111208', 'student', 'task_review', 'Mahnoor Ahmed', 'mahnoor.ahmed@example.com', '+923000445588', 4, 'Code review value', 'Review notes direct aur kaam ki thin. Un se mujhe samajh aya ke code ko aur clean kaise banana hai.', 'approved', now() - interval '130 days', now() - interval '130 days', now() - interval '130 days', now()),
('11111111-1111-1111-1111-111111111209', 'student', 'internship', 'Ali Raza', 'ali.raza@example.com', '+923334556677', 5, 'Got a Lahore internship', 'Physical internship ke baad Lahore ki aik software house me internship mil gayi, baad me paid opportunity bhi ban gayi.', 'approved', now() - interval '125 days', now() - interval '125 days', now() - interval '125 days', now()),
('11111111-1111-1111-1111-11111111120a', 'student', 'support', 'Mira Javed', 'mira.javed@example.com', '+923119991122', 4, 'Helpful support desk', 'Jab main stuck hui to support team ne kaafi jaldi help ki. Tone bhi professional thi aur response bhi clear tha.', 'approved', now() - interval '120 days', now() - interval '120 days', now() - interval '120 days', now()),
('11111111-1111-1111-1111-11111111120b', 'student', 'course', 'Ahsan Farooq', 'ahsan.farooq@example.com', '+923214778899', 5, 'Practical course flow', 'Course ka structure bohat practical tha. Aisa laga ke jo cheezen seekh rahe hain woh seedha interview aur project work me use hongi.', 'approved', now() - interval '115 days', now() - interval '115 days', now() - interval '115 days', now()),
('11111111-1111-1111-1111-11111111120c', 'student', 'mentor', 'Noor Fatima', 'noor.fatima@example.com', '+923001223344', 5, 'Good mentorship', 'Mentor ne career path aur CV/GitHub dono par clear guidance di. Mujhe next step samajhne me bohat help mili.', 'approved', now() - interval '110 days', now() - interval '110 days', now() - interval '110 days', now()),
('11111111-1111-1111-1111-11111111120d', 'student', 'task_review', 'Hassan Nadeem', 'hassan.nadeem@example.com', '+923334112244', 4, 'Review notes were useful', 'Review notes seedhi aur useful thin. Un se mujhe presentation aur coding style dono better karne me madad mili.', 'approved', now() - interval '105 days', now() - interval '105 days', now() - interval '105 days', now()),
('11111111-1111-1111-1111-11111111120e', 'student', 'internship', 'Laiba Khalid', 'laiba.khalid@example.com', '+923212334455', 5, 'Paid internship secured', 'Training ke baad mujhe paid internship mil gayi. Mujhe honestly laga ke ye program real career move tha.', 'approved', now() - interval '100 days', now() - interval '100 days', now() - interval '100 days', now()),
('11111111-1111-1111-1111-11111111120f', 'student', 'support', 'Zainab Qasim', 'zainab.qasim@example.com', '+923331110099', 5, 'Always responsive', 'Har stage par support available tha. Main kabhi aisa feel nahi hua ke mujhe akela chhor diya gaya ho.', 'approved', now() - interval '95 days', now() - interval '95 days', now() - interval '95 days', now()),
('11111111-1111-1111-1111-111111111210', 'student', 'course', 'Saad Mustafa', 'saad.mustafa@example.com', '+923114440077', 4, 'Good for beginners', 'Main bilkul basics se aya tha aur yahan se understanding kaafi strong hui. Software house ke kaam ka idea bhi mil gaya.', 'approved', now() - interval '90 days', now() - interval '90 days', now() - interval '90 days', now()),
('11111111-1111-1111-1111-111111111211', 'student', 'mentor', 'Iqra Sohail', 'iqra.sohail@example.com', '+923006667788', 5, 'Career guidance', 'Mentor ne interview prep aur career guidance di jo waqai kaam ayi. Shortlist hone me us ka role tha.', 'approved', now() - interval '85 days', now() - interval '85 days', now() - interval '85 days', now()),
('11111111-1111-1111-1111-111111111212', 'student', 'task_review', 'Abdullah Riaz', 'abdullah.riaz@example.com', '+923214009988', 5, 'Fast review cycle', 'Feedback fast mil jata tha, is liye main turant corrections kar leta tha. Learning ka flow break nahi hota tha.', 'approved', now() - interval '80 days', now() - interval '80 days', now() - interval '80 days', now()),
('11111111-1111-1111-1111-111111111213', 'student', 'internship', 'Hira Yousaf', 'hira.yousaf@example.com', '+923334889900', 4, 'Real internship exposure', 'Physical internship ki wajah se office work aur client communication ka real experience mila. Confidence kaafi increase hua.', 'approved', now() - interval '75 days', now() - interval '75 days', now() - interval '75 days', now()),
